code = """import pandas as pd
import json
from datetime import datetime

# Load data from previous query results
cases = pd.DataFrame(var_call_ILOU4pqmV1deBywkML0TEJkz)
accounts = pd.DataFrame(var_call_JRbMhCblgiTmZC065lEkUhVP)

# Normalize IDs by stripping leading '#' and whitespace
cases['accountid_clean'] = cases['accountid'].astype(str).str.strip().str.lstrip('#')
accounts['Id_clean'] = accounts['Id'].astype(str).str.strip().str.lstrip('#')

# Parse dates with utc
cases['createddate'] = pd.to_datetime(cases['createddate'], errors='coerce', utc=True)
cases['closeddate'] = pd.to_datetime(cases['closeddate'], errors='coerce', utc=True)

# Define past 6 quarters window based on today's date 2022-10-26
window_start = pd.to_datetime('2021-07-01T00:00:00Z')  # start of Q3 2021
window_end = pd.to_datetime('2022-10-26T23:59:59Z')

# Filter cases to closeddate within the 6-quarter window
cases = cases[(cases['closeddate'] >= window_start) & (cases['closeddate'] <= window_end)]

# Compute closure time in hours
cases['closure_hours'] = (cases['closeddate'] - cases['createddate']).dt.total_seconds() / 3600.0

# Merge with accounts to get ShippingState
merged = cases.merge(accounts[['Id_clean','ShippingState']], left_on='accountid_clean', right_on='Id_clean', how='left')

# Drop rows without ShippingState or with missing closure time
merged = merged.dropna(subset=['ShippingState','closure_hours'])

# Clean ShippingState whitespace
merged['ShippingState'] = merged['ShippingState'].astype(str).str.strip()

# Group by state and compute average closure time and counts
grp = merged.groupby('ShippingState').agg(avg_closure_hours=('closure_hours','mean'), case_count=('closure_hours','count')).reset_index()

# If no data, return None
if grp.shape[0] == 0:
    result = None
else:
    # Find minimal average closure time
    min_avg = grp['avg_closure_hours'].min()
    candidates = grp[grp['avg_closure_hours'] == min_avg]
    # If multiple, pick the one with highest case_count, then alphabetical
    candidates = candidates.sort_values(by=['case_count','ShippingState'], ascending=[False,True])
    best_state = candidates.iloc[0]['ShippingState']
    result = best_state

print("__RESULT__:")
print(json.dumps(result))"""

